// Form posts as application/x-www-form-urlencoded. n8n exposes the parsed
// fields under .body. Validate, normalize, and prep the IS payload + email.

const body = $input.first().json.body || {};
const email = (body.email || '').toString().trim().toLowerCase();
const magnet = (body.magnet || 'str-tax-loophole-explainer').toString().trim();
const landingPage = (body.landing_page || 'strmanuals.com/free').toString().trim();

const emailOk = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
if (!emailOk) {
  return [{ json: { ok: false, status: 400, reason: 'invalid_email', received: email } }];
}

// PDF is deployed by STRManuals/site/scripts/copy-pdfs-to-dist.mjs to
// /dl/{HASH}/free/tax-loophole-explainer.pdf — same hash gate that protects
// paid manuals. Set STRMANUALS_DOWNLOAD_HASH in n8n env (mirror of the
// value in STRManuals/site/.env).
const HASH = $env.STRMANUALS_DOWNLOAD_HASH;
if (!HASH) {
  return [{ json: { ok: false, status: 500, reason: 'missing_download_hash' } }];
}
const PDF_URL = `https://strmanuals.com/dl/${HASH}/free/tax-loophole-explainer.pdf`;
const CONFIRM_REDIRECT = 'https://strmanuals.com/free/?confirmed=1';

const emailBody = `Hi —\n\nHere is the 8-page STR tax-loophole explainer:\n\n${PDF_URL}\n\nThe full STR Tax Loophole Playbook ($) is at https://strmanuals.com/manuals/tax-01/ when you want the deep version.\n\nOver the next week, you will get:\n  Day 2 — the "what counts as 7 days" trap\n  Day 4 — material participation, the actual gate\n  Day 7 — a 48-hour subscriber-only price on the playbook\n\nUnsubscribe link is at the bottom of every email.\n\n— Daniel`;

return [{
  json: {
    ok: true,
    status: 200,
    email,
    magnet,
    landing_page: landingPage,
    ts: new Date().toISOString(),
    pdf_url: PDF_URL,
    confirm_redirect: CONFIRM_REDIRECT,
    email_subject: 'Your STR Tax Loophole Explainer (8 pages)',
    email_body: emailBody
  }
}];
